# Helper to build graph from adjacency list
def build_graph(adj_list):
    if not adj_list: return None
    nodes = [Node(i+1) for i in range(len(adj_list))]
    for i, neighbors in enumerate(adj_list):
        for n in neighbors:
            nodes[i].neighbors.append(nodes[n-1])
    return nodes[0]

def graph_to_adj(node):
    if not node: return []
    visited = {}
    result = []
    def dfs(n):
        if n.val in visited: return
        visited[n.val] = len(result)
        result.append([])
        for nei in n.neighbors:
            result[-1].append(nei.val)
            dfs(nei)
    dfs(node)
    return result

